# ============================================================
# 2. 修复后的注入函数 — 用"下一个日期的 id"定位对象结束
# ============================================================

def find_day_end_before(next_id_pos, content):
    """从 next_id 位置向前扫描，找到当前 CyberDay 对象的结束 }"""
    for i in range(next_id_pos - 1, -1, -1):
        ch = content[i]
        if ch == '}':
            return i
    return -1


def inject_coding_exercises(filepath, exercises_map, id_prefix):
    """将编程练习注入 TS 文件，使用可靠的下一个 id 定位法"""
    with open(filepath, 'r', encoding='utf-8') as f:
        content = f.read()

    # 收集所有 day_id 的位置
    day_positions = []
    for day_id in exercises_map:
        pos = -1
        for fmt in [f'id: "{day_id}"', f"id: '{day_id}'"]:
            p = content.find(fmt)
            if p != -1:
                pos = p
                break
        if pos != -1:
            day_positions.append((day_id, pos))

    # 按位置排序
    day_positions.sort(key=lambda x: x[1])

    modified = 0
    # 从最后一个开始处理（避免位置偏移）
    for idx in range(len(day_positions) - 1, -1, -1):
        day_id, day_start = day_positions[idx]
        exercises = exercises_map[day_id]

        # 找到下一个 day 的 id 作为边界
        # 实际上我们找 expertNotes 后的 }
        # 更简单：找下一个 id 的 { 前面的 }
        if idx + 1 < len(day_positions):
            next_id_pos = day_positions[idx + 1][1]
            end_pos = find_day_end_before(next_id_pos, content)
            if end_pos == -1:
                # fallback: 从下一个 id 往前扫找 }
                end_pos = content.rfind('}', day_start, next_id_pos)
        else:
            # 最后一个 day: 找到文件末尾的 ];
            last_bracket = content.rfind(']')
            if last_bracket > 0:
                # 往前找最近的 }
                end_pos = content.rfind('}', day_start, last_bracket)
            else:
                end_pos = -1

        if end_pos == -1:
            print(f"  警告: 找不到 {day_id} 的结束位置")
            continue

        # 检查是否已有 codingExercises
        segment = content[day_start:end_pos]
        if 'codingExercises' in segment:
            print(f"  跳过 {day_id}: 已有 codingExercises")
            continue

        # 在 closing } 之前插入
        exercises_json = json.dumps(exercises, ensure_ascii=False, separators=(',', ':'))
        injection = f',\n    codingExercises: {exercises_json}\n  '
        content = content[:end_pos] + injection + content[end_pos:]
        modified += 1
        print(f"  已注入 {day_id}: {len(exercises)} 道练习")

    if modified > 0:
        with open(filepath, 'w', encoding='utf-8') as f:
            f.write(content)
        print(f"\n共修改 {modified} 天, 已保存 {filepath}")
    else:
        print(f"\n无需修改 {filepath}")

    return modified


# ============================================================
# 3. 主流程
# ============================================================

def main():
    base = os.path.dirname(os.path.abspath(__file__))
    src = os.path.join(base, 'src', 'data')

    # AI 计划
    ai_file = os.path.join(src, 'cyberAi.ts')
    if os.path.exists(ai_file):
        print("=== 处理 AI 网络安全计划 ===")
        inject_coding_exercises(ai_file, AI_EXERCISES, 'ai')

    print("\n========== 完成 ==========")
    print("请运行: npx tsc --noEmit 检查编译")


if __name__ == '__main__':
    main()
